   396→}
   397→
   398→/* ---------- Page ---------- */
   399→
   400→export default function ProjectsPage() {
   401→  const [createOpen, setCreateOpen] = useState(false);
   402→  const { data, isLoading } = useSWR("projects", () => projectsApi.list());
   403→  const items = data?.data ?? [];
   404→
   405→  return (
   406→    <div className="flex flex-col gap-4 fade-in">
   407→      <div className="flex items-center justify-between">
   408→        <div>
   409→          <h1
   410→            style={{
   411→              fontFamily: "var(--font-fraunces)",
   412→              fontSize: "24px",
   413→              fontWeight: 700,
   414→              color: "#111113",
   415→            }}
   416→          >
   417→            Projects
   418→          </h1>
   419→          <p
   420→            className="mt-1 text-[13px] text-[#6b7280]"
   421→            style={{ fontFamily: "var(--font-dm-sans)" }}
   422→          >
   423→            Tracked software projects and their recent releases.
   424→          </p>
   425→        </div>
   426→        <button
   427→          onClick={() => setCreateOpen(true)}
   428→          className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   429→          style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   430→        >
   431→          <Plus className="h-3.5 w-3.5" />
   432→          New Project
   433→        </button>
   434→      </div>
   435→
   436→      {isLoading ? (
   437→        <p
   438→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   439→          style={{ fontFamily: "var(--font-fraunces)" }}
   440→        >
   441→          Loading...
   442→        </p>
