   444→        <div
   445→          className="flex flex-col items-center justify-center rounded-md border py-12"
   446→          style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   447→        >
   448→          <p
   449→            className="text-[14px] italic text-[#9ca3af]"
   450→            style={{ fontFamily: "var(--font-fraunces)" }}
   451→          >
   452→            No projects yet — create one to start tracking releases
   453→          </p>
   454→          <button
   455→            onClick={() => setCreateOpen(true)}
   456→            className="mt-4 flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   457→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   458→          >
   459→            <Plus className="h-3.5 w-3.5" />
   460→            New Project
   461→          </button>
   462→        </div>
   463→      ) : (
   464→        <div className="space-y-4">
   465→          {items.map((project) => (
   466→            <ProjectCard key={project.id} project={project} />
   467→          ))}
   468→        </div>
   469→      )}
   470→
   471→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   472→        <DialogContent className="sm:max-w-lg">
   473→          <DialogHeader>
   474→            <DialogTitle>Create Project</DialogTitle>
   475→          </DialogHeader>
   476→          <ProjectForm
   477→            title="Create Project"
   478→            onSubmit={async (result) => {
